#include "config.h"
#include "system.h"
#include "coretypes.h"
#include "backend.h"
#include "tree.h"
#include "gimple.h"
#include "cfghooks.h"
#include "tree-pass.h"
#include "cfgloop.h"
#include "dumpfile.h"

namespace {

/* Pass metadata */
const pass_data pass_data_count_bb =
{
  GIMPLE_PASS,                    /* type */
  "count_bb",                     /* name */
  OPTGROUP_NONE,                  /* optinfo_flags */
  TV_TREE_SSA_OTHER,              /* tv_id */
  (PROP_cfg),                     /* properties_required */
  0,                              /* properties_provided */
  0,                              /* properties_destroyed */
  0,                              /* todo_flags_start */
  0,                              /* todo_flags_finish */
};

/* Pass class definition */
class pass_count_bb : public gimple_opt_pass
{
public:
  pass_count_bb (gcc::context *ctxt)
    : gimple_opt_pass (pass_data_count_bb, ctxt)
  {}

  /* opt_pass methods: */
  opt_pass * clone () final override
  {
    return new pass_count_bb (m_ctxt);
  }

  bool gate (function *) final override
  {
    return true;  /* Always run this pass */
  }

  unsigned int execute (function *fun) final override
  {
    /* Count the number of basic blocks in this function */
    int bb_count = n_basic_blocks_for_fn (fun);

    /* Output debug information if dump_file is enabled */
    if (dump_file)
      {
        fprintf (dump_file,
                 "Function '%s' has %d basic blocks\n",
                 function_name (fun),
                 bb_count);
      }

    /* Return 0 to indicate no changes to the IR */
    return 0;
  }

}; // class pass_count_bb

} // anon namespace

/* Factory function to create a new instance of this pass */
gimple_opt_pass *
make_pass_count_bb (gcc::context *ctxt)
{
  return new pass_count_bb (ctxt);
}

